import{_ as e,c as s,o as i,ag as l}from"./chunks/framework.piE7uVCg.js";const h=JSON.parse('{"title":"Protections","description":"","frontmatter":{},"headers":[],"relativePath":"projets/domotique/protections.md","filePath":"projets/domotique/protections.md"}'),n={name:"projets/domotique/protections.md"};function a(r,t,o,d,c,p){return i(),s("div",null,[...t[0]||(t[0]=[l(`<h1 id="protections" tabindex="-1"><a href="./readme.html">Protections</a> <a class="header-anchor" href="#protections" aria-label="Permalink to &quot;[Protections](readme.md)&quot;">​</a></h1><h2 id="description" tabindex="-1">Description <a class="header-anchor" href="#description" aria-label="Permalink to &quot;Description&quot;">​</a></h2><h2 id="protections-contre-les-courts-circuits" tabindex="-1">Protections contre les courts circuits <a class="header-anchor" href="#protections-contre-les-courts-circuits" aria-label="Permalink to &quot;Protections contre les courts circuits&quot;">​</a></h2><ul><li>Utiliser un fusible réarmable (PTC) sur l’alim de chaque module (5V ou 3.3V)</li><li>Ajouter une résistance série faible (10–22 Ω) sur les lignes A et B</li><li>Prévoir un driver RS485 avec protection interne</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Alim 5V] --- [PTC Fuse] --- VCC module</span></span>
<span class="line"><span></span></span>
<span class="line"><span>RS485_A  --- [10Ω] --- MAX485_A</span></span>
<span class="line"><span>RS485_B  --- [10Ω] --- MAX485_B</span></span></code></pre></div><h2 id="protection-contre-les-surtensions-esd" tabindex="-1">Protection contre les surtensions / ESD <a class="header-anchor" href="#protection-contre-les-surtensions-esd" aria-label="Permalink to &quot;Protection contre les surtensions / ESD&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Protection</th><th style="text-align:left;">Rôle</th><th style="text-align:left;">À mettre entre...</th></tr></thead><tbody><tr><td style="text-align:left;">TVS Diode (SM712, PESD1CAN...)</td><td style="text-align:left;">Clampe les pics transitoires</td><td style="text-align:left;">Entre A/B et GND</td></tr><tr><td style="text-align:left;">Varistor</td><td style="text-align:left;">Absorbe surtensions prolongées</td><td style="text-align:left;">Entre A-B, A-GND, B-GND</td></tr><tr><td style="text-align:left;">Ferrite bead</td><td style="text-align:left;">Filtre les interférences EMI</td><td style="text-align:left;">En série sur A/B</td></tr><tr><td style="text-align:left;">Condensateurs 100nF</td><td style="text-align:left;">Filtrent les parasites haute fréquence</td><td style="text-align:left;">Vers GND</td></tr></tbody></table><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>          RS485_A o---[10Ω]---+---[TVS diode]--- GND</span></span>
<span class="line"><span>                             |</span></span>
<span class="line"><span>                         MAX485_A</span></span>
<span class="line"><span></span></span>
<span class="line"><span>          RS485_B o---[10Ω]---+---[TVS diode]--- GND</span></span>
<span class="line"><span>                             |</span></span>
<span class="line"><span>                         MAX485_B</span></span></code></pre></div><h2 id="protection-contre-les-inversions-de-polarite" tabindex="-1">Protection contre les inversions de polarité <a class="header-anchor" href="#protection-contre-les-inversions-de-polarite" aria-label="Permalink to &quot;Protection contre les inversions de polarité&quot;">​</a></h2><ul><li>Le bus RS485 est différentiel, mais certains modules crashent si on inverse A/B</li><li>Solution simple : prévoir un switch de sélection de polarité (ou jumper)</li><li>Ou coder un auto-scan au démarrage si pas de réponse → tester inversion</li></ul><h2 id="protection-de-l-alimentation" tabindex="-1">Protection de l&#39;alimentation <a class="header-anchor" href="#protection-de-l-alimentation" aria-label="Permalink to &quot;Protection de l&#39;alimentation&quot;">​</a></h2><p>Si tu partages l’alim 5V sur tout le bus :</p><ul><li>Mettre une diode Schottky pour éviter retour de courant</li><li>Utiliser un buck ou LDO local si la ligne est longue</li><li>Ajoute un PTC par module et un condensateur 100µF + 100nF par carte</li></ul><h2 id="resistances-de-terminaison-et-pull-up-pull-down" tabindex="-1">Résistances de terminaison et pull-up/pull-down <a class="header-anchor" href="#resistances-de-terminaison-et-pull-up-pull-down" aria-label="Permalink to &quot;Résistances de terminaison et pull-up/pull-down&quot;">​</a></h2><p>Obligatoire pour éviter les réflexions parasites :</p><table tabindex="0"><thead><tr><th style="text-align:left;">Type</th><th style="text-align:left;">Où ?</th><th style="text-align:left;">Valeur</th></tr></thead><tbody><tr><td style="text-align:left;">Terminaison</td><td style="text-align:left;">Aux 2 extrémités du bus</td><td style="text-align:left;">120 Ω entre A et B</td></tr><tr><td style="text-align:left;">Pull-up / Pull-down</td><td style="text-align:left;">Optionnel au maître</td><td style="text-align:left;">680 Ω A → VCC, B → GND</td></tr></tbody></table><h2 id="resume-check-list-de-protection-rs485" tabindex="-1">Résumé : check-list de protection RS485 <a class="header-anchor" href="#resume-check-list-de-protection-rs485" aria-label="Permalink to &quot;Résumé : check-list de protection RS485&quot;">​</a></h2><p>Par module :</p><ul><li>[ ] 10–22 Ω sur A/B</li><li>[ ] TVS diode ou varistor</li><li>[ ] Fusible réarmable PTC sur l’alim</li><li>[ ] Condensateurs de découplage (100nF + 10µF)</li><li>[ ] Résistance de terminaison si aux extrémités</li></ul><p>En bonus :</p><ul><li>[ ] Inversion A/B tolérée</li><li>[ ] LED de diagnostic communication</li><li>[ ] Shielding si câble long ou exposé</li></ul>`,21)])])}const m=e(n,[["render",a]]);export{h as __pageData,m as default};
